   451→/**
   452→ * Props for the Widget wrapper component
   453→ *
   454→ * Widgets are the primary dashboard building blocks. Each widget
   455→ * displays in a card with optional header, drag controls, and
   456→ * built-in loading/error state handling.
   457→ *
   458→ * @example
   459→ * ```tsx
   460→ * <Widget
   461→ *   id="weather"
   462→ *   title="Weather"
   463→ *   category="Information"
   464→ *   loading={isLoading}
   465→ *   error={fetchError}
   466→ *   onRefresh={refetch}
   467→ * >
   468→ *   <WeatherDisplay data={weatherData} />
   469→ * </Widget>
   470→ * ```
   471→ */
   472→export interface WidgetProps {
   473→  /** Unique identifier for the widget (used for persistence) */
   474→  id: string;
   475→  /** Display title shown in widget header */
   476→  title: string;
   477→  /** Category label (e.g., "Information", "Productivity") */
   478→  category?: string;
   479→  /** Additional CSS classes for the widget container */
   480→  className?: string;
   481→  /** Widget content - rendered when not loading/error */
   482→  children?: React.ReactNode;
   483→  /** Optional content displayed in header (e.g., weather stats) */
   484→  headerAccessory?: React.ReactNode;
   485→  /** Whether to show drag handle (default: true) */
   486→  draggable?: boolean;
   487→  /** Shows loading spinner instead of children when true */
   488→  loading?: boolean;
   489→  /** Shows error message with retry option when set */
   490→  error?: string | null;
   491→  /** Callback for retry/refresh button (enables refresh button in header) */
   492→  onRefresh?: () => void;
   493→}
