export interface BackupPreferences {
  // ... existing fields ...
  reminderPreference: 'every-session' | 'in-7-days' | 'monthly' | 'never';
  // ... rest ...
}
```

#### Step 2: Update BackupOnboardingModal

**File**: `src/components/BackupOnboardingModal.tsx`

```typescript
// Line 25, update ReminderPreference type
type ReminderPreference = 'every-session' | 'in-7-days' | 'monthly' | 'never';

// Line ~617-638, update reminder options to include 'monthly'
// Add to the options array:
{ id: 'monthly', label: 'Monthly', description: 'Remind me on the 1st of each month' },
```

#### Step 3: Update useBackupOnboarding Hook

**File**: `src/hooks/useBackupOnboarding.ts`

```typescript
// Add monthly handling after line 58
if (reminderPreference === 'monthly' && nextReminderDate) {
  const now = new Date();
  const reminderDate = new Date(nextReminderDate);

  if (now >= reminderDate) {
    markAsChecked();
    return true;
  }
}
```

#### Step 4: Create Utility Function for Date Calculation

**File**: `src/hooks/useBackupOnboarding.ts` (add at top)

```typescript
/**
 * Get ISO string for 1st of next month
 */
const getFirstOfNextMonth = (): string => {
  const now = new Date();
  const nextMonth = new Date(now.getFullYear(), now.getMonth() + 1, 1, 0, 0, 0, 0);
  return nextMonth.toISOString();
};
```

#### Step 5: Refactor OnboardingModal Step 4

**File**: `src/components/OnboardingModal.tsx`

Major changes to `renderCompletionStep()`:

```typescript
import { isFileSystemAccessSupported } from '../services/brainBackup';
import { useThemeStore } from '../stores/useThemeStore';

// Inside component, add state:
const [showSkipOptions, setShowSkipOptions] = useState(false);
const [selectedReminder, setSelectedReminder] = useState<'in-7-days' | 'monthly' | null>(null);
const updateBackupPreferences = useThemeStore((state) => state.updateBackupPreferences);
const [showBackupModal, setShowBackupModal] = useState(false);

const isFSASupported = isFileSystemAccessSupported();

// Helper to calculate next reminder date
const getNextReminderDate = (type: 'in-7-days' | 'monthly'): string => {
  if (type === 'in-7-days') {
    return new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString();
  }
  // Monthly: 1st of next month
  const now = new Date();
  return new Date(now.getFullYear(), now.getMonth() + 1, 1).toISOString();
};

const handleSkipWithReminder = () => {
  if (selectedReminder) {
    updateBackupPreferences({
      reminderPreference: selectedReminder,
      nextReminderDate: getNextReminderDate(selectedReminder),
    });
  }
  handleComplete();
};

const handleSkipForever = () => {
  updateBackupPreferences({
    reminderPreference: 'never',
    nextReminderDate: null,
  });
  handleComplete();
};

const handleSetupBackup = () => {
  setShowBackupModal(true);
};

const handleBackupComplete = () => {
  setShowBackupModal(false);
  handleComplete();
};
```

**New Step 4 JSX Structure**:

```tsx
const renderCompletionStep = () => (
  <div className="space-y-6">
    {/* Header */}
    <div className="text-center">
      <div className="flex items-center justify-center mb-4">
        <Sparkles className="h-12 w-12 text-primary-magenta" />
      </div>
      <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-2">
        You're All Set!
      </h2>
      <p className="text-text-light-secondary dark:text-text-dark-secondary">
        Ready to start organizing your life
      </p>
    </div>

    {/* Backup Section - Only show if FSA supported */}
    {isFSASupported && (
      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
        <div className="flex items-start gap-3 mb-4">
          <Shield className="h-6 w-6 text-primary-cyan shrink-0 mt-0.5" />
          <div>
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary mb-1">
              Protect Your Data
            </h3>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              Your data is stored in your browser. Enable auto-save to a cloud folder for automatic backups and sync across devices.
            </p>
          </div>
        </div>

        <button
          onClick={handleSetupBackup}
          className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-primary-cyan text-white rounded-lg hover:bg-primary-cyan/90 transition-colors font-medium"
        >
          <Shield className="h-4 w-4" />
          <span>Setup Auto-Save Now</span>
        </button>

        {/* Skip Options */}
        {!showSkipOptions ? (
          <button
            onClick={() => setShowSkipOptions(true)}
            className="w-full mt-2 text-sm text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
          >
            Maybe later...
          </button>
        ) : (
          <div className="mt-3 pt-3 border-t border-border-light dark:border-border-dark">
            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-2">
              When should we remind you?
            </p>
            <div className="space-y-2">
              {[
                { id: 'in-7-days', label: 'In 7 days' },
                { id: 'monthly', label: 'Monthly (1st of month)' },
              ].map((option) => (
                <button
                  key={option.id}
                  onClick={() => setSelectedReminder(option.id as 'in-7-days' | 'monthly')}
                  className={`w-full p-2 text-left text-sm rounded border transition-all ${
                    selectedReminder === option.id
                      ? 'border-primary-cyan bg-primary-cyan/10 text-text-light-primary dark:text-text-dark-primary'
                      : 'border-border-light dark:border-border-dark hover:border-primary-cyan/50'
                  }`}
                >
                  {option.label}
                </button>
              ))}
            </div>
            <div className="flex gap-2 mt-3">
              <button
                onClick={handleSkipWithReminder}
                disabled={!selectedReminder}
                className="flex-1 px-3 py-2 bg-primary-magenta text-white rounded text-sm font-medium disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Confirm
              </button>
              <button
                onClick={handleSkipForever}
                className="px-3 py-2 text-sm text-text-light-secondary dark:text-text-dark-secondary hover:text-status-error transition-colors"
              >
                Never remind
              </button>
            </div>
          </div>
        )}
      </div>
    )}

    {/* Non-FSA Browser Message */}
    {!isFSASupported && (
      <div className="bg-status-info/10 border border-status-info rounded-lg p-4">
        <p className="text-sm text-text-light-primary dark:text-text-dark-primary">
          <strong>Note:</strong> Auto-save requires Chrome, Edge, or Brave browser.
          You can manually export your data anytime from Settings.
        </p>
      </div>
    )}

    {/* Get Started Section */}
    <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-6">
      <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary text-center mb-4">
        Get Started
      </h3>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
        <button
          onClick={handleComplete}
          className="flex items-center justify-center gap-2 px-4 py-3 bg-primary-magenta text-white rounded-lg hover:bg-primary-magenta/90 transition-colors"
        >
          <FileText className="h-4 w-4" />
          <span className="font-medium">Create Your First Note</span>
        </button>
        <button
          onClick={handleComplete}
          className="flex items-center justify-center gap-2 px-4 py-3 bg-primary-cyan text-white rounded-lg hover:bg-primary-cyan/90 transition-colors"
        >
          <CheckSquare className="h-4 w-4" />
          <span className="font-medium">Create Your First Task</span>
        </button>
      </div>
      <p className="text-xs text-center text-text-light-secondary dark:text-text-dark-secondary mt-3">
        You can access all features from the sidebar on the left
      </p>
    </div>

    {/* Backup Modal (inline) */}
    <BackupOnboardingModal 
      isOpen={showBackupModal} 
      onClose={handleBackupComplete} 
    />
  </div>
);
```

#### Step 6: Update App.tsx to Remove Sequential Backup Modal

**File**: `src/App.tsx`

Remove the separate BackupOnboardingModal rendering since it's now launched from within OnboardingModal:

```tsx
// Lines 181-187, REMOVE:
// {/* Backup Onboarding Modal - only show after initial onboarding complete */}
// <BackupOnboardingModal isOpen={onboardingComplete && shouldShowModal} onClose={dismissModal} />

// KEEP for returning users who skipped initially:
{/* Backup Reminder Modal - for users who skipped during onboarding */}
{onboardingComplete && shouldShowModal && (
  <BackupOnboardingModal isOpen={shouldShowModal} onClose={dismissModal} />
)}
```

Actually, keep the backup modal for **returning users** who:
1. Completed onboarding but skipped backup
2. Have a reminder date that has passed

The change is: First-time users see backup option in OnboardingModal Step 4, returning users get reminded via the existing `useBackupOnboarding` hook logic.

